const filters = $("When Executed by Another Workflow").first().json;

const inventory = $input.all();

const results = inventory.filter(item => {
    const p = item.json;

    if (
        filters.category &&
        (p.Category || "").toLowerCase() !== filters.category.toLowerCase()
    ) {
        return false;
    }

    if (
        filters.brand &&
        (p.Brand || "").toLowerCase() !== filters.brand.toLowerCase()
    ) {
        return false;
    }

    if (
        filters.max_price &&
        Number(p.Price) > Number(filters.max_price)
    ) {
        return false;
    }

    if (
        filters.size &&
        (p.Size || "").toLowerCase() !== filters.size.toLowerCase()
    ) {
        return false;
    }

    if (filters.premium === true) {
        if ((p.Premium || "").toLowerCase() !== "yes") {
            return false;
        }
    }

    if (filters.in_stock_only) {
        if (Number(p.Stock || 0) <= 0) {
            return false;
        }
    }

    return true;
});

// Preserve customer information
return results.map(item => ({
    json: {
        customer_email: filters.customer_email,
        customer_query: filters.customer_query,
        ...item.json
    }
}));
